using System.Collections.ObjectModel;using System.Windows.Input;using OpennLayer.Infrastructure.Versioning;namespace OpennLayer.UI.ViewModels{public class MainViewModel{public ObservableCollection<string> Versions{get;}=new();public string SelectedVersion{get;set;}public string Status{get;set;}public ICommand LoadVersionsCommand{get;}public ICommand AttachCommand{get;}private readonly OpennLayer.Application.Services.TiaPortalService _svc;public MainViewModel(OpennLayer.Application.Services.TiaPortalService svc){_svc=svc;LoadVersionsCommand=new RelayCommand(_=>Load());AttachCommand=new RelayCommand(async _=>await Attach());}void Load(){Versions.Clear();foreach(var v in TiaVersionDetector.GetInstalledVersions()) Versions.Add(v);SelectedVersion=Versions.Count>0?Versions[0]:null;}async System.Threading.Tasks.Task Attach(){Status='Connecting';await _svc.AttachAsync(SelectedVersion);Status=$'Connected V{SelectedVersion}';}}} 
public class RelayCommand:System.Windows.Input.ICommand{private readonly System.Action<object> e;public RelayCommand(System.Action<object> e){this.e=e;}public event System.EventHandler CanExecuteChanged;public bool CanExecute(object p)=>true;public void Execute(object p)=>e(p);} 
